param([ValidateSet('coarse','fine')][string]$Profile='coarse',[string]$RunId='')
Set-StrictMode -Version Latest;$ErrorActionPreference='Stop';$projectRoot=(Resolve-Path (Join-Path $PSScriptRoot '..\..')).Path;$repoRoot=(Resolve-Path (Join-Path $projectRoot '..\..')).Path;$workspaceRoot=Split-Path -Parent $repoRoot;$artifactRoot=Join-Path $workspaceRoot 'artifacts\projects\rf_quadrupole_collision_cooling';$python=Join-Path $repoRoot '.venv\Scripts\python.exe';$contractSource=Join-Path $projectRoot 'config\rf_piecewise_swept_mesh_candidate.json';& $python (Join-Path $projectRoot 'analysis\validate_rf_piecewise_swept_mesh.py');if($LASTEXITCODE-ne 0){throw 'Piecewise contract failed.'}
$contractDocument=Get-Content -LiteralPath $contractSource -Raw -Encoding UTF8|ConvertFrom-Json;if($contractDocument.status-ne'approved_for_solver_validation'){throw 'Piecewise swept strategy is closed; further solver runs are forbidden by the frozen contract.'}
if([string]::IsNullOrWhiteSpace($RunId)){$RunId=(Get-Date -Format 'yyyyMMdd_HHmmss')+"__analysis__comsol__rf-piecewise-swept__${Profile}"};& $python (Join-Path $repoRoot 'common\contracts\artifact_naming.py') run $RunId;if($LASTEXITCODE-ne 0){throw "Invalid run id: $RunId"};$runDir=Join-Path $artifactRoot "runs\$RunId";if(Test-Path -LiteralPath $runDir){throw "Run exists: $runDir"};$inputDir=Join-Path $runDir 'inputs';$resultDir=Join-Path $runDir 'results';$logDir=Join-Path $runDir 'logs';New-Item -ItemType Directory -Force -Path $inputDir,$resultDir,$logDir|Out-Null
$task=Join-Path $inputDir 'build_rf_piecewise_swept_mesh.m';$analysis=Join-Path $inputDir 'analyze_rf_continuous_shield_3d.py';$contract=Join-Path $inputDir 'rf_piecewise_swept_mesh_candidate.json';$resolved=Join-Path $inputDir 'resolved_design.json';$runner=Join-Path $inputDir 'run_rf_piecewise_swept_mesh.ps1.txt';Copy-Item (Join-Path $PSScriptRoot 'build_rf_piecewise_swept_mesh.m') $task;Copy-Item (Join-Path $projectRoot 'analysis\analyze_rf_continuous_shield_3d.py') $analysis;Copy-Item $contractSource $contract;Copy-Item (Join-Path $projectRoot 'config\resolved_design_official.json') $resolved;Copy-Item $PSCommandPath $runner;$field=Join-Path $resultDir 'rf_piecewise_swept_field_samples.csv';$report=Join-Path $logDir 'comsol_rf_piecewise_swept_mesh.txt';$summary=Join-Path $runDir 'summary.json';$runConfig=Join-Path $runDir 'run_config.json';$writer=Join-Path $repoRoot 'common\contracts\write_run_manifest.py'
[ordered]@{schema_version=1;run_id=$RunId;project='rf_quadrupole_collision_cooling';mode='rf_full_device_piecewise_swept_field';project_root=$repoRoot;inputs=[ordered]@{task=$task;analysis=$analysis;contract=$contract;resolved_design=$resolved;runner=$runner};parameters=[ordered]@{profile=$Profile;fine_core_radius_mm=8.0;fine_core_hmax_mm=0.2;outer_hmax_mm=1.0;particle_tracking=$false;model_saved=$false};formal_gate_passed=$false}|ConvertTo-Json -Depth 6|Set-Content $runConfig -Encoding UTF8;[ordered]@{schema_version=1;role='rf_piecewise_swept_summary';status='interrupted'}|ConvertTo-Json|Set-Content $summary -Encoding UTF8;& $python $writer --run-config $runConfig --status interrupted --software 'COMSOL 6.4' --software 'MATLAB R2025b' --software 'Python 3.11'
$names=@('RF_PIECEWISE_FIELD_CSV','RF_PIECEWISE_CONTRACT','RF_PIECEWISE_RESOLVED','RF_PIECEWISE_PROFILE');$old=@{};foreach($name in $names){$old[$name]=[Environment]::GetEnvironmentVariable($name)};try{try{$env:RF_PIECEWISE_FIELD_CSV=$field;$env:RF_PIECEWISE_CONTRACT=$contract;$env:RF_PIECEWISE_RESOLVED=$resolved;$env:RF_PIECEWISE_PROFILE=$Profile;& (Join-Path $repoRoot 'common\comsol\run_comsol_r2025b.ps1') -TaskScript $task -ReportPath $report;if($LASTEXITCODE-ne 0){throw 'COMSOL piecewise task failed.'}}finally{foreach($name in $names){[Environment]::SetEnvironmentVariable($name,$old[$name])}};& $python $analysis --input $field --output-dir $resultDir;if($LASTEXITCODE-ne 0){throw 'Piecewise field analysis failed.'}}catch{[ordered]@{schema_version=1;role='rf_piecewise_swept_summary';status='failed';reason=$_.Exception.Message}|ConvertTo-Json|Set-Content $summary -Encoding UTF8;& $python $writer --run-config $runConfig --status failed --software 'COMSOL 6.4' --software 'MATLAB R2025b' --software 'Python 3.11';throw};[ordered]@{schema_version=1;role='rf_piecewise_swept_summary';status='success';field_characterized=$true;particle_tracking_allowed=$false}|ConvertTo-Json|Set-Content $summary -Encoding UTF8;$outputs=@($field,(Join-Path $resultDir 'rf_continuous_shield_3d_harmonics.csv'),(Join-Path $resultDir 'rf_continuous_shield_3d_metrics.json'),$report,$summary);$args=@($writer,'--run-config',$runConfig,'--status','success','--software','COMSOL 6.4','--software','MATLAB R2025b','--software','Python 3.11');foreach($o in $outputs){$args+=@('--output',$o)};& $python @args;if($LASTEXITCODE-ne 0){throw 'Final manifest failed.'};Write-Output "STATUS=PASS RUN_ID=$RunId PROFILE=$Profile"
